import React, { useState, useEffect } from 'react';
import { 
  StyleSheet, 
  View, 
  Text, 
  Modal, 
  TextInput, 
  TouchableOpacity, 
  ScrollView 
} from 'react-native';
import { UtilityType, ExtractedData } from '../types';

interface VerifyModalProps {
  visible: boolean;
  data: ExtractedData | null;
  onConfirm: (data: ExtractedData) => void;
  onCancel: () => void;
}

export default function VerifyModal({ visible, data, onConfirm, onCancel }: VerifyModalProps) {
  const [editedData, setEditedData] = useState<ExtractedData | null>(null);

  useEffect(() => {
    if (data) setEditedData(data);
  }, [data]);

  if (!editedData) return null;

  return (
    <Modal visible={visible} transparent animationType="fade">
      <View style={styles.overlay}>
        <View style={styles.container}>
          <Text style={styles.title}>Verify Receipt Data</Text>
          <Text style={styles.subtitle}>Please check and correct the values if needed.</Text>

          <ScrollView style={styles.form}>
            <View style={styles.inputGroup}>
              <Text style={styles.label}>Date (YYYY-MM-DD)</Text>
              <TextInput 
                style={styles.input}
                value={editedData.date}
                onChangeText={(text) => setEditedData({...editedData, date: text})}
              />
            </View>

            <View style={styles.inputGroup}>
              <Text style={styles.label}>Utility Type</Text>
              <View style={styles.tabContainer}>
                <TouchableOpacity 
                  style={[styles.tab, editedData.utilityType === UtilityType.ELECTRIC && styles.activeTab]}
                  onPress={() => setEditedData({...editedData, utilityType: UtilityType.ELECTRIC})}
                >
                  <Text style={[styles.tabText, editedData.utilityType === UtilityType.ELECTRIC && styles.activeTabText]}>Electric</Text>
                </TouchableOpacity>
                <TouchableOpacity 
                  style={[styles.tab, editedData.utilityType === UtilityType.WATER && styles.activeTab]}
                  onPress={() => setEditedData({...editedData, utilityType: UtilityType.WATER})}
                >
                  <Text style={[styles.tabText, editedData.utilityType === UtilityType.WATER && styles.activeTabText]}>Water</Text>
                </TouchableOpacity>
              </View>
            </View>

            <View style={styles.inputGroup}>
              <Text style={styles.label}>Consumption ({editedData.utilityType === UtilityType.ELECTRIC ? 'kWh' : 'm³'})</Text>
              <TextInput 
                style={styles.input}
                keyboardType="numeric"
                value={editedData.consumption.toString()}
                onChangeText={(text) => setEditedData({...editedData, consumption: parseFloat(text) || 0})}
              />
            </View>

            <View style={styles.inputGroup}>
              <Text style={styles.label}>Total Amount (₱)</Text>
              <TextInput 
                style={styles.input}
                keyboardType="numeric"
                value={editedData.total.toString()}
                onChangeText={(text) => setEditedData({...editedData, total: parseFloat(text) || 0})}
              />
            </View>
          </ScrollView>

          <View style={styles.actions}>
            <TouchableOpacity style={styles.cancelButton} onPress={onCancel}>
              <Text style={styles.cancelButtonText}>Cancel</Text>
            </TouchableOpacity>
            <TouchableOpacity style={styles.confirmButton} onPress={() => onConfirm(editedData)}>
              <Text style={styles.confirmButtonText}>Confirm & Save</Text>
            </TouchableOpacity>
          </View>
        </View>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  overlay: {
    flex: 1,
    backgroundColor: 'rgba(15, 23, 42, 0.5)',
    justifyContent: 'center',
    padding: 20,
  },
  container: {
    backgroundColor: '#fff',
    borderRadius: 24,
    padding: 24,
    maxHeight: '80%',
  },
  title: {
    fontSize: 20,
    fontWeight: 'bold',
    color: '#0F172A',
    marginBottom: 8,
  },
  subtitle: {
    fontSize: 14,
    color: '#64748B',
    marginBottom: 20,
  },
  form: {
    marginBottom: 24,
  },
  inputGroup: {
    marginBottom: 16,
  },
  label: {
    fontSize: 12,
    fontWeight: '600',
    color: '#64748B',
    marginBottom: 6,
    textTransform: 'uppercase',
  },
  input: {
    backgroundColor: '#F8FAFC',
    borderWidth: 1,
    borderColor: '#E2E8F0',
    borderRadius: 12,
    padding: 12,
    fontSize: 16,
    color: '#0F172A',
  },
  tabContainer: {
    flexDirection: 'row',
    backgroundColor: '#F1F5F9',
    borderRadius: 12,
    padding: 4,
  },
  tab: {
    flex: 1,
    paddingVertical: 10,
    alignItems: 'center',
    borderRadius: 8,
  },
  activeTab: {
    backgroundColor: '#fff',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.05,
    shadowRadius: 4,
    elevation: 2,
  },
  tabText: {
    fontSize: 14,
    fontWeight: '600',
    color: '#64748B',
  },
  activeTabText: {
    color: '#2563EB',
  },
  actions: {
    flexDirection: 'row',
    gap: 12,
  },
  cancelButton: {
    flex: 1,
    paddingVertical: 14,
    alignItems: 'center',
    borderRadius: 12,
    backgroundColor: '#F1F5F9',
  },
  cancelButtonText: {
    color: '#475569',
    fontWeight: '600',
  },
  confirmButton: {
    flex: 2,
    paddingVertical: 14,
    alignItems: 'center',
    borderRadius: 12,
    backgroundColor: '#2563EB',
  },
  confirmButtonText: {
    color: '#fff',
    fontWeight: '600',
  },
});
